#!/usr/bin/perl -w
use strict;
print qq(Content-type text/html\r\n\r\n);  ## print headers in perl, use \r instead of "\n" for windows compatibility.
my $comment = $ENV{'QUERY_STRING'};   # get the query string parameters from environment variables (usually passed by httpd) and store it into a variable named 'COMMENT'. If you are testing this locally using CGI scripts on your machine, replace COMMENT with QUERY_STRING in print statement.
print qq(<div>$comment</div>\r\n); ## escape the double quotes by printing them as is and use \r instead of "\n" for windows compatibility (they are escaped inside).